const body = $('Receive Scan Results').first().json.body;

const packages = body.installed_packages || [];
const pythonPackages = body.python_packages || [];
const openPorts = body.open_ports || [];

const softwareList = [];

const skipPrefixes = ['lib', 'linux-', 'perl-', 'fonts-', 'ucf', 'debconf', 'tzdata', 'gcc-', 'cpp-', 'binutils', 'x11-', 'xorg', 'gnome-', 'kde-'];

for (const pkg of packages) {
  const name = pkg.name.toLowerCase();
  const skip = skipPrefixes.some(prefix => name.startsWith(prefix));
  if (!skip) {
    softwareList.push({ name: pkg.name, version: pkg.version, type: 'system' });
  }
}

for (const pkg of pythonPackages) {
  softwareList.push({ name: pkg.name, version: pkg.version, type: 'python' });
}

for (const port of openPorts) {
  if (port.service && port.service !== 'unknown') {
    softwareList.push({ name: port.service, version: port.version || '', type: 'service' });
  }
}

return softwareList.map((item, index) => ({
  json: item,
  pairedItem: { item: 0 }
}));

const items = $input.all();
const allPackages = $('Extract Software List').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const pkg = allPackages[i]?.json || {};

  if (!item.json || !Array.isArray(item.json.vulnerabilities)) continue;

  for (const vuln of item.json.vulnerabilities) {
    if (!vuln || !vuln.cve) continue;

    const cve = vuln.cve;
    const cvssV31 = cve.metrics?.cvssMetricV31?.[0]?.cvssData;
    const cvssV30 = cve.metrics?.cvssMetricV30?.[0]?.cvssData;
    const cvssV2 = cve.metrics?.cvssMetricV2?.[0]?.cvssData;
    const cvssData = cvssV31 || cvssV30 || cvssV2;

    results.push({
      json: {
        cve_id: cve.id || '',
        description: cve.descriptions?.find(d => d.lang === 'en')?.value || '',
        cvss_score: cvssData?.baseScore || 0,
        cvss_severity: cvssData?.baseSeverity || '',
        published: cve.published || '',
        last_modified: cve.lastModified || '',
        software_name: pkg.name || '',
        software_version: pkg.version || '',
        software_type: pkg.type || ''
      },
      pairedItem: { item: i }  // ← only change
    });
  }
}

return results.length > 0 ? results : [{ json: { cve_id: null, skip: true }, pairedItem: { item: 0 } }];

const items = $input.all();
const kevList = $('Fetch CISA KEV List').all()[0]?.json?.vulnerabilities || [];

return items.map((item, index) => {
  const epssData = item.json.data?.[0] || {};
  const checkCVE = $('Check Existing CVE').all()[index]?.json || {};
  const filterCVE = $('Filter Matching CVEs').all()[index]?.json || {};
  const cveId = epssData.cve || checkCVE.cve_id || null;
  const kevEntry = cveId ? kevList.find(k => k.cveID === cveId) : null;

  return {
    json: {
      cve_id: cveId,
      description: filterCVE.description || null,
      cvss_score: filterCVE.cvss_score || null,
      cvss_severity: filterCVE.cvss_severity || null,
      software_name: filterCVE.software_name || null,
      software_version: filterCVE.software_version || null,
      software_type: filterCVE.software_type || null,
      epss_score: parseFloat(epssData.epss) || 0,
      epss_percentile: parseFloat(epssData.percentile) || 0,
      kev_listed: kevEntry ? true : false,
      kev_date_added: kevEntry ? kevEntry.dateAdded : null,
    },
    pairedItem: { item: index }
  };
});

