const patchData = $json.output;
const cve = $('Merge CVE + PoC').item.json;
const prepValidation = $('Prepare Validation Input').item.json;
const prepPatch = $('Prepare Patch Input').item.json;

const cvssScore = Number(cve.cvss_score) || 0;
const kevListed = cve.kev_listed;
const patchAvailable = patchData.patch_available;
const hitlRequired = (cvssScore >= 9 && !patchAvailable) || (cvssScore >= 9 && kevListed);

return {
  json: {
    cve_id: cve.cve_id,
    affected_software: cve.software_name,
    affected_version: cve.software_version,
    cvss_score: cvssScore,
    epss_score: cve.epss_score,
    kev_listed: kevListed,
    exploit_available: cve.exploit_available,
    exploitable_on_this_system: prepPatch.exploitable,
    patch_available: patchAvailable,
    fixed_version: patchData.fixed_version || null,
    upgrade_command: patchData.upgrade_command || null,
    workaround: patchData.workaround || null,
    vendor_advisory_url: patchData.vendor_advisory_url || null,
    claude_analysis: JSON.stringify({
      root_cause: prepValidation.root_cause,
      attack_steps: prepValidation.attack_steps,
      exploitation_conditions: prepValidation.exploitation_conditions,
      real_world_risk: prepValidation.real_world_risk,
