const items = $input.all();

return items.map((item, index) => {
  const osv = item.json;
  const kevData = $('KEV Lookup').all()[index]?.json || {};

  let patch_available = false;
  let fixed_version = null;

  for (const vuln of osv.vulns || []) {
    for (const aff of vuln.affected || []) {
      for (const range of aff.ranges || []) {
        const fixedEvent = (range.events || []).find(e => e.fixed !== undefined);
        if (fixedEvent) {
          patch_available = true;
          fixed_version = fixedEvent.fixed;
        }
      }
    }
  }

  return {
    json: {
      ...kevData,
      patch_available,
      fixed_version
    }
  };
});
